mapper.select:
SELECT FROM projects p LEFT JOIN clients c ON p.client_id = c.id
(p.project_name LIKE CONCAT('%', #{keyword}, '%') OR c.name LIKE CONCAT('%', #{keyword}, '%'))
AND p.status = #{status}
ORDER BY p.created_at DESC
LIMIT #{limit}

SELECT id, project_id, original_filename
FROM project_files
WHERE project_id IN (
    SELECT id FROM projects
    WHERE created_date >= #{start_date}
      AND created_date <= #{end_date}
)

SELECT
    COALESCE(SUM(total_amount), 0) AS total_amount,
    COALESCE(SUM(commission), 0) AS total_commission
FROM projects
WHERE created_date >= #{start_date}
  AND created_date <= #{end_date}

SELECT COALESCE(SUM(e.amount), 0) AS total_expenses
FROM expenses e
JOIN projects p ON e.project_id = p.id
WHERE p.created_date >= #{start_date}
  AND p.created_date <= #{end_date}
